20:       model: process.env.GEMINI_MODEL || "gemini-1.5-flash",
21:       temperature,
22:     });
23:   }
24: 
25:   // default: openai
26:   if (!process.env.OPENAI_API_KEY) {
27:     throw new Error(
28:       "OPENAI_API_KEY is missing. Set LLM_PROVIDER=gemini or add an OpenAI key to .env"
29:     );
30:   }
31:   return new ChatOpenAI({
32:     apiKey: process.env.OPENAI_API_KEY,
33:     model: process.env.OPENAI_MODEL || "gpt-4o-mini",
34:     temperature,
35:   });
36: }
