38: /**
39:  * Ask the LLM to return strict JSON matching a shape we describe in the prompt.
40:  * Strips markdown code fences defensively and parses.
41:  */
42: export async function askForJSON(llm, systemPrompt, userPrompt) {
43:   const response = await llm.invoke([
44:     { role: "system", content: systemPrompt },
45:     { role: "user", content: userPrompt },
46:   ]);
47: 
48:   const raw = typeof response.content === "string"
49:     ? response.content
50:     : JSON.stringify(response.content);
51: 
52:   const cleaned = raw.replace(/```json/gi, "").replace(/```/g, "").trim();
53: 
54:   try {
55:     return JSON.parse(cleaned);
56:   } catch (err) {
57:     // Fallback: try to locate the first {...} block
58:     const match = cleaned.match(/\{[\s\S]*\}/);
59:     if (match) {
60:       try {
61:         return JSON.parse(match[0]);
62:       } catch (_) {
63:         // fall through
64:       }
65:     }
66:     throw new Error(
67:       `LLM did not return valid JSON. Raw response:\n${raw.slice(0, 500)}`
68:     );
69:   }
70: }
