import { useState } from "react";
import CompanyForm from "./components/CompanyForm.jsx";
import Loader from "./components/Loader.jsx";
import ResultsView from "./components/ResultsView.jsx";

export default function App() {
  const [company, setCompany] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [dark, setDark] = useState(true);

  // Call the backend API with the company name
  async function analyze() {
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ company }),
      });

      const data = await response.json();

      if (!response.ok) {
        setError(data.error || "Something went wrong. Please try again.");
      } else {
        setResult(data);
      }
    } catch (err) {
      setError(err.message || "Could not connect to the server.");
    }

    setLoading(false);
  }

  // Download the full analysis as a text file
  function downloadReport() {
    if (!result) return;

    const d = result.decision || {};
    const o = result.overview || {};
    const f = result.financials || {};
    const n = result.news || {};
    const c = result.competitors || {};
    const r = result.risks || {};

    const lines = [
      `Investment Research Report — ${result.company}`,
      "=".repeat(50),
      "",
      "OVERVIEW",
      `Company: ${o.companyName}`,
      `Industry: ${o.industry}`,
      `CEO: ${o.ceo}`,
      `Founded: ${o.founded}`,
      `HQ: ${o.headquarters}`,
      `Business Model: ${o.businessModel}`,
      `Summary: ${o.summary}`,
      "",
      "FINANCIALS",
      `Revenue: ${f.revenue}`,
      `Net Income: ${f.netIncome}`,
      `Market Cap: ${f.marketCap}`,
      `Revenue Growth: ${f.revenueGrowthTrend}`,
      `Profitability: ${f.profitabilityTrend}`,
      "",
      "NEWS",
      `Sentiment: ${n.sentiment}`,
      "Headlines:",
      ...(n.headlines || []).map((h) => `  - ${h}`),
      "",
      "COMPETITORS",
      `Key Rivals: ${(c.competitors || []).join(", ")}`,
      `Positioning: ${c.positioning}`,
      "",
      "RISKS",
      "Risks:",
      ...(r.risks || []).map((x) => `  - ${x}`),
      "Opportunities:",
      ...(r.opportunities || []).map((x) => `  + ${x}`),
      "",
      "FINAL DECISION",
      `Decision: ${d.decision}`,
      `Confidence: ${d.confidence}%`,
      `Reasoning: ${d.reasoning}`,
      "Pros:",
      ...(d.pros || []).map((x) => `  + ${x}`),
      "Cons:",
      ...(d.cons || []).map((x) => `  - ${x}`),
    ];

    const text = lines.join("\n");
    const blob = new Blob([text], { type: "text/plain" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.href = url;
    link.download = `${result.company}-research-report.txt`;
    link.click();

    URL.revokeObjectURL(url);
  }

  return (
    <div className={dark ? "dark" : ""}>
      <div className="min-h-screen bg-ink text-paper font-body">
        <div className="max-w-3xl mx-auto px-4 py-10 md:py-16">

          {/* Header */}
          <header className="flex items-start justify-between mb-10">
            <div>
              <h1 className="font-display font-semibold text-3xl md:text-4xl text-paper leading-tight">
                AI Investment
                <br />
                Research Agent
              </h1>
              <p className="text-muted text-sm mt-3 max-w-md">
                Enter a company name. The agent researches it across six steps and
                gives you an invest or pass recommendation with reasoning.
              </p>
            </div>
            <button
              onClick={() => setDark(!dark)}
              className="font-mono text-xs px-3 py-1.5 rounded border border-line text-muted
                         hover:text-paper hover:border-gold transition-colors shrink-0"
            >
              {dark ? "LIGHT" : "DARK"}
            </button>
          </header>

          {/* Search form */}
          <div className="mb-8">
            <CompanyForm
              value={company}
              onChange={setCompany}
              onSubmit={analyze}
              loading={loading}
            />
          </div>

          {/* Loading state */}
          {loading && <Loader company={company} />}

          {/* Error message */}
          {error && (
            <div className="border border-pass/40 bg-pass/10 rounded-md p-4 font-mono text-sm text-pass">
              Error: {error}
            </div>
          )}

          {/* Results */}
          {result && !loading && (
            <>
              {/* Download button */}
              <div className="flex justify-end mb-4">
                <button
                  onClick={downloadReport}
                  className="font-mono text-xs px-4 py-2 rounded border border-gold text-gold
                             hover:bg-gold hover:text-ink transition-colors"
                >
                  ↓ Download Report
                </button>
              </div>
              <ResultsView result={result} />
            </>
          )}

          {/* Empty state */}
          {!result && !loading && !error && (
            <div className="border border-dashed border-line rounded-md p-10 text-center text-muted font-mono text-xs">
              No analysis yet — enter a company above
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

import { getLLM, askForJSON } from "./services/llm.js";
import { webSearch } from "./services/search.js";

// Create one shared LLM instance used by all nodes
const llm = getLLM({ temperature: 0.2 });

// If any node fails, we set state.error.
// This helper checks that so later nodes can skip themselves.
function hasError(state) {
  return Boolean(state.error);
}

// Step 1: Get a basic company overview (who they are, what they do)
export async function researchNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(
      `${state.company} company overview business model CEO industry headquarters`
    );

    const data = await askForJSON(
      llm,
      `You are an equity research analyst. Return ONLY valid JSON with no markdown, matching exactly:
{"companyName": string, "industry": string, "ceo": string, "businessModel": string, "founded": string, "headquarters": string, "summary": string}
If web search context is unavailable, use your general knowledge and mention it in "summary".`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { overview: data };
  } catch (err) {
    return { error: `researchNode failed: ${err.message}` };
  }
}

// Step 2: Pull financial numbers — revenue, profit, market cap
export async function financialNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(
      `${state.company} revenue net income profit margin market capitalization financial results latest`
    );

    const data = await askForJSON(
      llm,
      `You are a financial analyst. Return ONLY valid JSON matching exactly:
{"revenue": string, "netIncome": string, "marketCap": string, "revenueGrowthTrend": string, "profitabilityTrend": string, "summary": string}
Use the most recent figures you know. If exact data isn't available, give an estimate and say so.`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { financials: data };
  } catch (err) {
    return { error: `financialNode failed: ${err.message}` };
  }
}

// Step 3: Check recent news and figure out if sentiment is positive, neutral, or negative
export async function newsNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(`${state.company} latest news 2026`);

    const data = await askForJSON(
      llm,
      `You are a markets news analyst. Return ONLY valid JSON matching exactly:
{"headlines": [string], "sentiment": "positive"|"neutral"|"negative", "summary": string}
"headlines" should be 3-5 short bullet-style items.`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { news: data };
  } catch (err) {
    return { error: `newsNode failed: ${err.message}` };
  }
}

// Step 4: Find the main competitors and where this company stands vs them
export async function competitorNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(`${state.company} main competitors market share`);

    const data = await askForJSON(
      llm,
      `You are a competitive-strategy analyst. Return ONLY valid JSON matching exactly:
{"competitors": [string], "positioning": string, "summary": string}
"competitors" should list 2-5 key rivals.`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { competitors: data };
  } catch (err) {
    return { error: `competitorNode failed: ${err.message}` };
  }
}

// Step 5: Identify risks and opportunities based on everything gathered so far
export async function riskNode(state) {
  if (hasError(state)) return {};

  try {
    // This node uses data from previous nodes — no extra web search needed
    const context = `Company: ${state.company}
Overview: ${JSON.stringify(state.overview)}
Financials: ${JSON.stringify(state.financials)}
News: ${JSON.stringify(state.news)}
Competitors: ${JSON.stringify(state.competitors)}`;

    const data = await askForJSON(
      llm,
      `You are a risk analyst. Return ONLY valid JSON matching exactly:
{"risks": [string], "opportunities": [string], "summary": string}
"risks" and "opportunities" should each have 3-5 concise bullet items based on the context provided.`,
      context
    );

    return { risks: data };
  } catch (err) {
    return { error: `riskNode failed: ${err.message}` };
  }
}

// Step 6: Make the final call — INVEST or PASS — with a confidence score and reasoning
export async function decisionNode(state) {
  if (hasError(state)) return {};

  try {
    const context = `Company: ${state.company}
Overview: ${JSON.stringify(state.overview)}
Financials: ${JSON.stringify(state.financials)}
News: ${JSON.stringify(state.news)}
Competitors: ${JSON.stringify(state.competitors)}
Risks & Opportunities: ${JSON.stringify(state.risks)}`;

    const data = await askForJSON(
      llm,
      `You are the lead portfolio manager. Read all the research below and return ONLY valid JSON matching exactly:
{"decision": "INVEST"|"PASS", "confidence": number, "pros": [string], "cons": [string], "reasoning": string}
"confidence" is 0-100. Keep "reasoning" to 2-4 sentences.`,
      context
    );

    return { decision: data };
  } catch (err) {
    return { error: `decisionNode failed: ${err.message}` };
  }
}

import { StateGraph, START, END } from "@langchain/langgraph";
import { AgentState } from "./state.js";
import {
  researchNode,
  financialNode,
  newsNode,
  competitorNode,
  riskNode,
  decisionNode,
} from "./nodes.js";

// This builds the agent graph — basically a pipeline where each step
// feeds its output into the next one.
//
// The order is:
//   research → financials → news → competitors → risk → decision
//
// If any step fails (sets state.error), the rest skip themselves
// so we get a clean error instead of a broken partial result.

export function buildGraph() {
  const graph = new StateGraph(AgentState)
    .addNode("researchStep", researchNode)
    .addNode("financialStep", financialNode)
    .addNode("newsStep", newsNode)
    .addNode("competitorStep", competitorNode)
    .addNode("riskStep", riskNode)
    .addNode("decisionStep", decisionNode)
    .addEdge(START, "researchStep")
    .addEdge("researchStep", "financialStep")
    .addEdge("financialStep", "newsStep")
    .addEdge("newsStep", "competitorStep")
    .addEdge("competitorStep", "riskStep")
    .addEdge("riskStep", "decisionStep")
    .addEdge("decisionStep", END);

  return graph.compile();
}

import "dotenv/config";
import { ChatOpenAI } from "@langchain/openai";
import { ChatGoogleGenerativeAI } from "@langchain/google-genai";

// Pick the right LLM based on what's in the .env file
// Supports "openai" or "gemini"
export function getLLM({ temperature = 0.3 } = {}) {
  const provider = (process.env.LLM_PROVIDER || "openai").toLowerCase();

  if (provider === "gemini") {
    if (!process.env.GEMINI_API_KEY) {
      throw new Error("GEMINI_API_KEY is missing from .env");
    }
    return new ChatGoogleGenerativeAI({
      apiKey: process.env.GEMINI_API_KEY,
      model: process.env.GEMINI_MODEL || "gemini-2.0-flash",
      temperature,
    });
  }

  // Default: OpenAI
  if (!process.env.OPENAI_API_KEY) {
    throw new Error("OPENAI_API_KEY is missing from .env");
  }
  return new ChatOpenAI({
    apiKey: process.env.OPENAI_API_KEY,
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    temperature,
  });
}

// Sends a message to the LLM and parses the response as JSON.
// The LLM is instructed to return plain JSON (no markdown fences),
// but we strip them anyway just in case.
export async function askForJSON(llm, systemPrompt, userPrompt) {
  const response = await llm.invoke([
    { role: "system", content: systemPrompt },
    { role: "user", content: userPrompt },
  ]);

  // response.content is the raw text the model returned
  const raw =
    typeof response.content === "string"
      ? response.content
      : JSON.stringify(response.content);

  // Strip any markdown code fences the model might have added
  const cleaned = raw.replace(/```json/gi, "").replace(/```/g, "").trim();

  try {
    return JSON.parse(cleaned);
  } catch (err) {
    // If straight parse fails, try to grab the first {...} block in the text
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (_) {
        // still failed, fall through
      }
    }
    throw new Error(`LLM did not return valid JSON. Raw response:\n${raw.slice(0, 500)}`);
  }
}

import "dotenv/config";
import axios from "axios";

// This runs a Tavily web search and returns the results as a plain text string.
// If there's no TAVILY_API_KEY in .env, it returns null and the nodes
// just fall back to the LLM's own training knowledge.
export async function webSearch(query, { maxResults = 5 } = {}) {
  const apiKey = process.env.TAVILY_API_KEY;

  if (!apiKey) return null; // no key = skip search, no crash

  try {
    const { data } = await axios.post(
      "https://api.tavily.com/search",
      {
        api_key: apiKey,
        query,
        search_depth: "basic",
        max_results: maxResults,
        include_answer: true,
      },
      { timeout: 15000 }
    );

    // Build a simple text summary from the results
    const parts = [];
    if (data.answer) parts.push(`Summary: ${data.answer}`);

    for (const result of data.results || []) {
      parts.push(`- [${result.title}] ${result.content} (source: ${result.url})`);
    }

    return parts.join("\n");
  } catch (err) {
    console.error("Tavily search failed:", err.message);
    return null; // don't crash the whole request if search fails
  }
}

import { Router } from "express";
import { buildGraph } from "./graph.js";

const router = Router();

// Build the agent graph once when the server starts.
// Every request reuses the same compiled graph.
const agent = buildGraph();

// POST /api/analyze — main endpoint
// Expects: { company: "Tesla" }
// Returns: all the research data + a final invest/pass decision
router.post("/analyze", async (req, res) => {
  const { company } = req.body || {};

  if (!company || typeof company !== "string" || !company.trim()) {
    return res.status(400).json({ error: "Please provide a company name." });
  }

  try {
    const result = await agent.invoke({ company: company.trim() });

    // If any node set an error, send it back as a 502
    if (result.error) {
      return res.status(502).json({ error: result.error });
    }

    // Send the full research result back to the frontend
    return res.json({
      company: result.company,
      overview: result.overview,
      financials: result.financials,
      news: result.news,
      competitors: result.competitors,
      risks: result.risks,
      decision: result.decision,
    });
  } catch (err) {
    console.error(err);
    return res.status(500).json({ error: err.message || "Internal server error" });
  }
});

// GET /api/health — simple check to confirm the server is alive
router.get("/health", (req, res) => {
  res.json({ status: "ok" });
});

export default router;

import { Annotation } from "@langchain/langgraph";

// This defines the shared state object that gets passed between every node.
// Each node reads what it needs and writes back its own piece.
// The reducer (_, b) => b just means "always take the newest value".
export const AgentState = Annotation.Root({
  company: Annotation({ reducer: (_, b) => b, default: () => "" }),

  overview: Annotation({ reducer: (_, b) => b, default: () => null }),
  financials: Annotation({ reducer: (_, b) => b, default: () => null }),
  news: Annotation({ reducer: (_, b) => b, default: () => null }),
  competitors: Annotation({ reducer: (_, b) => b, default: () => null }),
  risks: Annotation({ reducer: (_, b) => b, default: () => null }),
  decision: Annotation({ reducer: (_, b) => b, default: () => null }),

  // If any node fails, it sets this field so the rest can skip
  error: Annotation({ reducer: (_, b) => b, default: () => null }),
});

