import { Annotation } from "@langchain/langgraph";

// LangGraph requires each field to have a reducer and a default value.
// The reducer just decides what to do when a node writes a new value.
// I always want the newest value, so the reducer just returns it.
// Wrapping this in field() avoids writing the same thing for every property.
function field(startValue = null) {
  return Annotation({
    reducer: (_, newValue) => newValue,
    default: () => startValue,
  });
}

// This is the data that gets passed from one step to the next.
// Each step reads what it needs and adds its own result.
// By the end of the pipeline, this object has everything filled in.
export const AgentState = Annotation.Root({
  company:     field(""),   // the company name the user typed
  overview:    field(),     // filled by step 1 — who they are
  financials:  field(),     // filled by step 2 — revenue, profit, market cap
  news:        field(),     // filled by step 3 — headlines + sentiment
  competitors: field(),     // filled by step 4 — rivals + positioning
  risks:       field(),     // filled by step 5 — risks and opportunities
  decision:    field(),     // filled by step 6 — INVEST or PASS
  error:       field(),     // if any step fails, it puts the error here
});

import { StateGraph, START, END } from "@langchain/langgraph";
import { AgentState } from "./state.js";
import {
  researchNode,
  financialNode,
  newsNode,
  competitorNode,
  riskNode,
  decisionNode,
} from "./nodes.js";

// This builds the pipeline. LangGraph calls it a "graph" because
// each step is a node and the arrows between them are edges.
//
// My pipeline is linear — one step feeds into the next:
//   research → financials → news → competitors → risk → decision
//
// If a step fails and sets state.error, the remaining steps check for
// that and skip themselves (see nodes.js).

export function buildGraph() {
  const graph = new StateGraph(AgentState)
    .addNode("researchStep", researchNode)
    .addNode("financialStep", financialNode)
    .addNode("newsStep", newsNode)
    .addNode("competitorStep", competitorNode)
    .addNode("riskStep", riskNode)
    .addNode("decisionStep", decisionNode)
    .addEdge(START, "researchStep")
    .addEdge("researchStep", "financialStep")
    .addEdge("financialStep", "newsStep")
    .addEdge("newsStep", "competitorStep")
    .addEdge("competitorStep", "riskStep")
    .addEdge("riskStep", "decisionStep")
    .addEdge("decisionStep", END);

  return graph.compile();
}

import { getLLM, askForJSON } from "./services/llm.js";
import { webSearch } from "./services/search.js";

// One LLM instance shared across all steps.
// Temperature 0.2 means less random / more factual responses.
const llm = getLLM({ temperature: 0.2 });

// If a previous step already failed, skip this one.
// This way we don't make more API calls after something breaks.
function hasError(state) {
  return Boolean(state.error);
}


// Step 1 — Research
// Goal: find out who this company is, what they do, and who runs them.
export async function researchNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(
      `${state.company} company overview business model CEO industry headquarters`
    );

    const data = await askForJSON(
      llm,
      `You are an equity research analyst. Return ONLY valid JSON, no markdown, matching exactly:
{"companyName": string, "industry": string, "ceo": string, "businessModel": string, "founded": string, "headquarters": string, "summary": string}
If web search context is unavailable, use your general knowledge and mention it in "summary".`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { overview: data };
  } catch (err) {
    return { error: `researchNode failed: ${err.message}` };
  }
}


// Step 2 — Financials
// Goal: get revenue, profit, market cap, and the general growth trend.
export async function financialNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(
      `${state.company} revenue net income profit margin market capitalization financial results latest`
    );

    const data = await askForJSON(
      llm,
      `You are a financial analyst. Return ONLY valid JSON matching exactly:
{"revenue": string, "netIncome": string, "marketCap": string, "revenueGrowthTrend": string, "profitabilityTrend": string, "summary": string}
Use the most recent figures you know. If exact data isn't available, give an estimate and say so.`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { financials: data };
  } catch (err) {
    return { error: `financialNode failed: ${err.message}` };
  }
}


// Step 3 — News
// Goal: what's been in the news lately and is it positive or negative?
export async function newsNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(`${state.company} latest news 2026`);

    const data = await askForJSON(
      llm,
      `You are a markets news analyst. Return ONLY valid JSON matching exactly:
{"headlines": [string], "sentiment": "positive"|"neutral"|"negative", "summary": string}
"headlines" should be 3-5 short bullet-style items.`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { news: data };
  } catch (err) {
    return { error: `newsNode failed: ${err.message}` };
  }
}


// Step 4 — Competitors
// Goal: who are the main competitors and how does this company compare to them?
export async function competitorNode(state) {
  if (hasError(state)) return {};

  try {
    const searchResults = await webSearch(`${state.company} main competitors market share`);

    const data = await askForJSON(
      llm,
      `You are a competitive-strategy analyst. Return ONLY valid JSON matching exactly:
{"competitors": [string], "positioning": string, "summary": string}
"competitors" should list 2-5 key rivals.`,
      `Company: ${state.company}\n\nWeb search context:\n${searchResults || "(no live search available)"}`
    );

    return { competitors: data };
  } catch (err) {
    return { error: `competitorNode failed: ${err.message}` };
  }
}


// Step 5 — Risk
// Goal: based on everything we've found so far, what are the risks and opportunities?
// This step doesn't do a web search — it reads the previous steps' output instead.
export async function riskNode(state) {
  if (hasError(state)) return {};

  try {
    const context = `Company: ${state.company}
Overview: ${JSON.stringify(state.overview)}
Financials: ${JSON.stringify(state.financials)}
News: ${JSON.stringify(state.news)}
Competitors: ${JSON.stringify(state.competitors)}`;

    const data = await askForJSON(
      llm,
      `You are a risk analyst. Return ONLY valid JSON matching exactly:
{"risks": [string], "opportunities": [string], "summary": string}
"risks" and "opportunities" should each have 3-5 concise bullet items based on the context provided.`,
      context
    );

    return { risks: data };
  } catch (err) {
    return { error: `riskNode failed: ${err.message}` };
  }
}


// Step 6 — Decision
// Goal: look at everything and make a final call — INVEST or PASS.
// Also give a confidence score (0-100), pros, cons, and a short reasoning paragraph.
export async function decisionNode(state) {
  if (hasError(state)) return {};

  try {
    const context = `Company: ${state.company}
Overview: ${JSON.stringify(state.overview)}
Financials: ${JSON.stringify(state.financials)}
News: ${JSON.stringify(state.news)}
Competitors: ${JSON.stringify(state.competitors)}
Risks & Opportunities: ${JSON.stringify(state.risks)}`;

    const data = await askForJSON(
      llm,
      `You are the lead portfolio manager. Read all the research below and return ONLY valid JSON matching exactly:
{"decision": "INVEST"|"PASS", "confidence": number, "pros": [string], "cons": [string], "reasoning": string}
"confidence" is 0-100. Keep "reasoning" to 2-4 sentences.`,
      context
    );

    return { decision: data };
  } catch (err) {
    return { error: `decisionNode failed: ${err.message}` };
