import "dotenv/config";
import { ChatOpenAI } from "@langchain/openai";
import { ChatGoogleGenerativeAI } from "@langchain/google-genai";

// Reads the .env file and returns the right LLM object.
// I support both Gemini and OpenAI so it's easy to switch.
export function getLLM({ temperature = 0.3 } = {}) {
  const provider = (process.env.LLM_PROVIDER || "openai").toLowerCase();

  if (provider === "gemini") {
    if (!process.env.GEMINI_API_KEY) {
      throw new Error("GEMINI_API_KEY is missing from .env");
    }
    return new ChatGoogleGenerativeAI({
      apiKey: process.env.GEMINI_API_KEY,
      model: process.env.GEMINI_MODEL || "gemini-2.0-flash-lite",
      temperature,
    });
  }

  // Default to OpenAI if LLM_PROVIDER is not set or is "openai"
  if (!process.env.OPENAI_API_KEY) {
    throw new Error("OPENAI_API_KEY is missing from .env");
  }
  return new ChatOpenAI({
    apiKey: process.env.OPENAI_API_KEY,
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    temperature,
  });
}

// Sends a message to the LLM and parses the response as JSON.
// I tell the model to return plain JSON in the system prompt,
// but sometimes it wraps it in markdown code fences anyway.
// This function strips those out before parsing.
export async function askForJSON(llm, systemPrompt, userPrompt) {
  const response = await llm.invoke([
    { role: "system", content: systemPrompt },
    { role: "user", content: userPrompt },
  ]);

  // response.content is just the text the model returned
  const raw =
    typeof response.content === "string"
      ? response.content
      : JSON.stringify(response.content);

  // Strip markdown fences like ```json ... ``` just in case
  const cleaned = raw.replace(/```json/gi, "").replace(/```/g, "").trim();

  try {
    return JSON.parse(cleaned);
  } catch (err) {
    // Sometimes the model adds extra text before/after the JSON.
    // Try to grab just the {...} block.
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (_) {
        // still didn't work, give up
      }
    }
    throw new Error(`LLM did not return valid JSON. Raw response:\n${raw.slice(0, 500)}`);
  }
}

import "dotenv/config";
import axios from "axios";

// Does a web search using Tavily and returns the results as a plain text string.
// If there's no TAVILY_API_KEY in .env, it just returns null.
// The calling code then falls back to the LLM's own knowledge.
// This way the app works without Tavily — it's optional, not required.
export async function webSearch(query, { maxResults = 5 } = {}) {
  const apiKey = process.env.TAVILY_API_KEY;

  // No key = skip the search entirely
  if (!apiKey) return null;

  try {
    const { data } = await axios.post(
      "https://api.tavily.com/search",
      {
        api_key: apiKey,
        query,
        search_depth: "basic",
        max_results: maxResults,
        include_answer: true,
      },
      { timeout: 15000 }
    );

    // Turn the results into a readable text block
    const parts = [];

    if (data.answer) {
      parts.push(`Summary: ${data.answer}`);
    }

    for (const result of data.results || []) {
      parts.push(`- [${result.title}] ${result.content} (source: ${result.url})`);
    }

    return parts.join("\n");
  } catch (err) {
    // If the search fails for any reason, just return null.
    // We don't want a search timeout to crash the whole analysis.
    console.error("Tavily search failed:", err.message);
    return null;
  }
}

import { Router } from "express";
import { buildGraph } from "./graph.js";

const router = Router();

// Build the pipeline once at startup.
// Every request uses the same compiled graph — no need to rebuild it each time.
const agent = buildGraph();


// POST /api/analyze
// This is the main endpoint. The frontend sends { company: "Tesla" }
// and gets back a full research report as JSON.
router.post("/analyze", async (req, res) => {
  const { company } = req.body || {};

  if (!company || typeof company !== "string" || !company.trim()) {
    return res.status(400).json({ error: "Please provide a company name." });
  }

  try {
    // Run all 6 steps and wait for the final state
    const result = await agent.invoke({ company: company.trim() });

    // If any step failed, send the error back
    if (result.error) {
      return res.status(502).json({ error: result.error });
    }

    // Otherwise send everything the frontend needs
    return res.json({
      company: result.company,
      overview: result.overview,
      financials: result.financials,
      news: result.news,
      competitors: result.competitors,
      risks: result.risks,
      decision: result.decision,
    });
  } catch (err) {
    console.error(err);
    return res.status(500).json({ error: err.message || "Internal server error" });
  }
});


// GET /api/health
// Just a quick check to confirm the server is running.
router.get("/health", (req, res) => {
  res.json({ status: "ok" });
});

export default router;

