const fs = require('fs');
const path = require('path');

try {
  // Move frontend source files to root
  const frontendPath = path.join(__dirname, 'frontend');
  if (fs.existsSync(frontendPath)) {
    const files = fs.readdirSync(frontendPath);
    for (const file of files) {
      if (file === 'node_modules') continue;
      // move file to root
      try {
        fs.renameSync(path.join(frontendPath, file), path.join(__dirname, file));
      } catch(e) {
        console.log(`Could not move ${file}`);
      }
    }
  }

  // Move backend/src to api
  const backendSrcPath = path.join(__dirname, 'backend', 'src');
  const apiPath = path.join(__dirname, 'api');
  if (fs.existsSync(backendSrcPath)) {
    if (!fs.existsSync(apiPath)) {
        fs.renameSync(backendSrcPath, apiPath);
    }
  }

  // Clean up
  console.log("Restructure successful.");
} catch (e) {
  console.error(e);
}

