import "dotenv/config";
import { ChatOpenAI } from "@langchain/openai";
import { ChatGoogleGenerativeAI } from "@langchain/google-genai";

// Build the OpenAI model instance (if key is available)
function getOpenAI() {
  if (!process.env.OPENAI_API_KEY) return null;
  return new ChatOpenAI({
    apiKey: process.env.OPENAI_API_KEY,
    model: process.env.OPENAI_MODEL || "gpt-4o-mini",
    temperature: 0.3,
  });
}

// Build the Gemini model instance (if key is available)
function getGemini() {
  if (!process.env.GEMINI_API_KEY) return null;
  return new ChatGoogleGenerativeAI({
    apiKey: process.env.GEMINI_API_KEY,
    model: process.env.GEMINI_MODEL || "gemini-2.0-flash-lite",
    temperature: 0.3,
  });
}

// Returns [primaryLLM, fallbackLLM] based on LLM_PROVIDER in .env
// Primary is tried first. If it hits a rate limit, the fallback kicks in.
export function getLLMs() {
  const provider = (process.env.LLM_PROVIDER || "openai").toLowerCase();

  const openai = getOpenAI();
  const gemini = getGemini();

  if (provider === "gemini") {
    if (!gemini) throw new Error("GEMINI_API_KEY is missing from .env");
    return [gemini, openai]; // gemini first, openai as fallback
  }

  // Default: openai first, gemini as fallback
  if (!openai) throw new Error("OPENAI_API_KEY is missing from .env");
  return [openai, gemini];
}

// Check if an error is a quota/rate-limit error (429)
function isQuotaError(err) {
  const msg = err?.message || "";
  return (
    msg.includes("429") ||
    msg.includes("quota") ||
    msg.includes("rate limit") ||
    msg.includes("Too Many Requests")
  );
}

// Parse raw LLM text into JSON (strips markdown fences if needed)
function parseJSON(raw) {
  const cleaned = raw.replace(/```json/gi, "").replace(/```/g, "").trim();
  try {
    return JSON.parse(cleaned);
  } catch (err) {
    // try to grab just the {...} block if there's surrounding text
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
    throw new Error(`LLM did not return valid JSON:\n${raw.slice(0, 500)}`);
  }
}

// Sends a prompt to the primary LLM and parses the response as JSON.
// If the primary hits a rate limit (429), it automatically retries with the fallback.
export async function askForJSON(systemPrompt, userPrompt) {
  const [primary, fallback] = getLLMs();

  async function callLLM(llm) {
    const response = await llm.invoke([
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt },
    ]);
    const raw =
      typeof response.content === "string"
        ? response.content
        : JSON.stringify(response.content);
    return parseJSON(raw);
  }

  try {
    return await callLLM(primary);
  } catch (err) {
    // If primary hit a quota limit and we have a fallback, try it
    if (isQuotaError(err) && fallback) {
      console.warn("Primary LLM quota hit — switching to fallback provider.");
      return await callLLM(fallback);
    }
    throw err; // any other error, just re-throw
  }
}

